	// The client key file for the targets.
	KeyFile string `yaml:"key_file,omitempty" json:"key_file,omitempty"`

	// CARef is the name of the secret within the secret manager to use as the CA cert.
	CARef string `yaml:"ca_ref,omitempty" json:"ca_ref,omitempty"`

	// CertRef is the name of the secret within the secret manager to use as the client cert.
	CertRef string `yaml:"cert_ref,omitempty" json:"cert_ref,omitempty"`

	// KeyRef is the name of the secret within the secret manager to use as the client key.
	KeyRef string `yaml:"key_ref,omitempty" json:"key_ref,omitempty"`

	// Used to verify the hostname for the targets.
	ServerName string `yaml:"server_name,omitempty" json:"server_name,omitempty"`

	// Disable target certificate validation.
	InsecureSkipVerify bool `yaml:"insecure_skip_verify" json:"insecure_skip_verify"`

	// Minimum TLS version.
